INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$1837e1bd-a80d-4d45-8634-d4f4823fb044$tag$, $tag$2026010100020$tag$, $tag$Gabriel Coordenador Uoas (5516993833272)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"01/01/2026 17:12:13"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"01/01/2026 17:12:14"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 17:12:15"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/6956d540397cd4409909f103)","time":"01/01/2026 17:12:48"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:53:40"},{"role":"client","text":"Oi, Karina, como vai voce????","time":"02/01/2026 08:09:48"},{"role":"client","text":"Me conte se consigo, como graduado em cinco graduações, concluir este bacharelado em Teologia, reconhecido pelo MEC, EaD, em tempo recorde, em seis meses.","time":"02/01/2026 08:10:29"},{"role":"agent","text":"*Karina Pimentel:* Olá!","time":"02/01/2026 08:23:39","feedback":"🤝 Humanização & Rapport: Ótimo início. Lembre-se de primeiro entender o momento do cliente antes de qualquer script."},{"role":"agent","text":"*Karina Pimentel:* Em 6 meses não, teria de cumprir os prazos das atividades. Prazo total 3 anos! ","time":"02/01/2026 08:24:22","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Ja sou graduado, entao deixa, sao direitos meus violados por voces.","time":"02/01/2026 08:25:04"},{"role":"client","text":"Estou cursando mais duas graduações ead, cada uma tradicionalmente é quatro anos, para quem nao é formado, para mim, estou cursando as duas em apenas um ano.","time":"02/01/2026 08:25:38"},{"role":"client","text":"Indague ai para a coordenação de curso mais informações, ou vc esta mal informada, ou a ies de voces nao respeita a legislação.","time":"02/01/2026 08:26:18"},{"role":"agent","text":"*Karina Pimentel:* Vou passar para meu supervisor as suas solicitações ok!","time":"02/01/2026 08:28:29","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Lhe retornarei assim que ele responder ok!","time":"02/01/2026 08:30:44","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Tudo bem, agradeço.","time":"02/01/2026 08:33:37"},{"role":"agent","text":"*Karina Pimentel:* Sr Gabriel, poderia realizar a analise das disciplinas já cursadas e eliminar as já concluídas! Desde que sejam reconhecidas pelo MEC!","time":"02/01/2026 10:20:38","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Com certeza. Estou ciente deste meu direito. Já o consegui em várias universidades.","time":"02/01/2026 10:21:52"},{"role":"agent","text":"*Karina Pimentel:* Benção!","time":"02/01/2026 10:30:07","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar o formulário!","time":"02/01/2026 10:30:24","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* 📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"02/01/2026 10:30:49","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Obrigado.","time":"02/01/2026 10:31:20"},{"role":"agent","text":"*Karina Pimentel:* De nada!","time":"02/01/2026 10:37:08","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Qualquer duvida estou a disposição!","time":"02/01/2026 10:37:25","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nGabriel Coordenador Uoas, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 16:38:01"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"05/01/2026 10:29:21"},{"role":"client","text":"Sua sessão expirou!","time":"05/01/2026 10:31:22"}]$tag$, $tag$2026-01-01 17:12:13+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 10, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_c