INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$feeb33b2-ef49-490d-a84e-cddc09e7fc66$tag$, $tag$2026010100021$tag$, $tag$PASTOR PAULO COSTA (5511941081133)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia EAD e quero mais informações.","time":"01/01/2026 17:35:08"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"01/01/2026 17:35:09"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 17:35:10"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:53:42"},{"role":"client","text":"Como funciona","time":"02/01/2026 08:14:20"},{"role":"agent","text":"*Karina Pimentel:* A nossa *Graduação em Teologia EAD* é Bacharelado reconhecido pelo MEC ( *bit.ly/3LlEgJS* ), com a duração de 3 anos.\n\nNo formato EAD, as aulas são ao vivo e gravadas e ficam à disposição do aluno no Ambiente Virtual de Aprendizagem, para assistir no seu tempo. As aulas ao vivo terão dia e horário definidos previamente e poderão ser assistidas posteriormente, pois ficarão gravadas.\n\nO aluno tem acesso aos materiais disponibilizados por nossos professores, tem encontros remotos com tutores, através da Plataforma Virtual da FICV (Plataforma Moodle), além de contar com materiais de apoio acadêmico-científico.","time":"02/01/2026 08:18:54","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* 🎓 Graduação EAD em Teologia por apenas R$ 399,70/mês! 🤩 Aproveite a condição especial: 20% de desconto na pontualidade durante toda a graduação, reduzindo o valor para R$ 319,76 por mês! 🎉 Usando o cupom *BOLSA20*\n\n✨ Sem taxa de matrícula! A primeira mensalidade é paga no ato da inscrição, e a próxima apenas no mês de início das aulas.\n\n🤑 Valor promocional: Semestralidade por R$ 1.918,56!\n\n⚠ Atenção: O valor mensal pode variar de acordo com a data de matrícula:\n\nMatrículas realizadas até em JANEIRO: 6 mensalidades de R$ 319,76 = R$ 1.918,56\nMatrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 383,71 = R$ 1.918,56\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 479,64 = R$ 1.918,56\n\n🗓️ Início das aulas: Fevereiro de 2026 📚💻","time":"02/01/2026 08:19:13","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"02/01/2026 15:50:38","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nPASTOR PAULO COSTA, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 15:50:42"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"05/01/2026 08:12:22"},{"role":"client","text":"Sua sessão expirou!","time":"05/01/2026 08:14:23"}]$tag$, $tag$2026-01-01 17:35:08+00$tag$, FALSE, FALSE, 6.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 5, 10, 5, 2, 9, 3, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$5d094787-8337-4e40-9326-77b815a75041$tag$, $tag$2026010100025$tag$, $tag$Joelma Alves de meireles (5583991406933)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Direito e quero mais informações.","time":"01/01/2026 19:08:53"},{"role":"client","text":"Por favor aguarde, em breve uma das nossas Consultoras lhe passará todas as informações.","time":"01/01/2026 19:08:54"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 19:08:55"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:53:45"},{"role":"client","text":"Bom dia","time":"02/01/2026 10:03:55"},{"role":"agent","text":"*Karina Pimentel:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"02/01/2026 10:05:30","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"02/01/2026 10:05:56","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"As iniciam quando","time":"02/01/2026 10:08:44"},{"role":"client","text":"Vcs recebem transferidos","time":"02/01/2026 10:09:07"},{"role":"client","text":"?","time":"02/01/2026 10:09:12"},{"role":"agent","text":"*Karina Pimentel:* Fevereiro","time":"02/01/2026 11:00:21","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* Sim, somente realizar a analise das disciplinas!","time":"02/01/2026 11:00:41","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* \n 📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"02/01/2026 11:01:08","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Ok","time":"02/01/2026 13:12:00"},{"role":"client","text":"Atendimento Finalizado!\n\nJoelma Alves de meireles, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 17:43:37"},{"role":"client","text":"Sua sessão irá expirar em 2 minutos!","time":"05/01/2026 13:10:02"},{"role":"client","text":"Sua sessão expirou!","time":"05/01/2026 13:12:03"}]$tag$, $tag$2026-01-01 19:08:53+00$tag$, FALSE, FALSE, 6.6, $tag$2026-03-01 16:46:57.607947+00$tag$, 7, 10, 5, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$f9679d00-c2b9-481e-b7be-d1101e11c215$tag$, $tag$2026010100030$tag$, $tag$Paulo Bomfim (351933668141)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"01/01/2026 20:37:18"},{"role":"client","text":"🌟 Boa noite Paulo Bomfim! Que alegria ter você aqui com a gente! 🙌","time":"01/01/2026 20:37:19"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"01/01/2026 20:37:23"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"01/01/2026 20:37:27"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"01/01/2026 20:37:31"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"01/01/2026 20:37:37"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"01/01/2026 20:37:42"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"01/01/2026 20:37:43"},{"role":"client","text":"Sim, concordo","time":"01/01/2026 20:38:18"},{"role":"client","text":"✅ Obrigado, Paulo Bomfim! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"01/01/2026 20:38:19"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"01/01/2026 20:38:23"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"01/01/2026 20:38:46"},{"role":"client","text":"Olá! Paulo Bomfim!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"01/01/2026 20:38:47"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"01/01/2026 20:38:51"},{"role":"client","text":"Saber sobre os cursos","time":"01/01/2026 20:39:06"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"01/01/2026 20:39:10"},{"role":"client","text":"Pós-Graduação","time":"01/01/2026 20:39:20"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"01/01/2026 20:39:24"},{"role":"client","text":"Novo Testamento","time":"01/01/2026 20:39:39"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"01/01/2026 20:39:40"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"01/01/2026 20:39:44"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"01/01/2026 20:40:06"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"01/01/2026 20:40:06"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"01/01/2026 20:40:07"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 07:53:47"},{"role":"agent","text":"*Karina Pimentel:*  *Pós-graduação em Teologia Bíblica e Exegética do Novo Testamento*\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 440h.\n\n*DISCIPLINAS*\nContamos com um total de 12 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"02/01/2026 08:05:04","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*   \n O valor de investimento na Pós-graduação em Novo Testamento está em 16 mensalidades de *R$ 359,37.\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026.","time":"02/01/2026 08:06:36","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 287,50.\nVamos garantir a sua vaga? 😊","time":"02/01/2026 08:07:00","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Bom dia","time":"02/01/2026 08:13:23"},{"role":"client","text":"Tudo bem graças a Deus","time":"02/01/2026 08:13:37"},{"role":"client","text":"Tenho formação teológica bacharelado, porém  meu curso  não  tem reconhecimento  mec\nTenho  interesse  no curso por conhecer a grade curricular  me despertou","time":"02/01/2026 08:15:50"},{"role":"client","text":"Posso  realizar  o mesmo","time":"02/01/2026 08:16:05"},{"role":"client","text":"Não  tenho como objetivo profissional e sim eclesiástica","time":"02/01/2026 08:16:40"},{"role":"agent","text":"*Karina Pimentel:* Segue a matriz curricular do curso de Teologia *bit.ly/3xljQgl*","time":"02/01/2026 08:16:47","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:*   Ficou alguma dúvida? O que está faltando para você dar esse passo e ingressar no curso? Tenho certeza de que será transformador em sua vida. 😊","time":"02/01/2026 15:50:28","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Atendimento Finalizado!\n\nPaulo Bomfim, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 15:50:30"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"02/01/2026 15:50:32"},{"role":"client","text":"5","time":"02/01/2026 15:52:28"},{"role":"client","text":"👉 Se quiser, você também pode deixar um comentário:\n✍️ \"O que podemos melhorar para te atender ainda melhor?\"\n\nDeseja deixar um comentário?\n\n1 - Sim\n2 - Não\n","time":"02/01/2026 15:52:29"},{"role":"client","text":"2","time":"02/01/2026 15:52:49"},{"role":"client","text":"Paulo Bomfim, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n\nAté mais!","time":"02/01/2026 15:52:50"}]$tag$, $tag$2026-01-01 20:37:18+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 5, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
