INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$d985a009-6f69-4bf8-9616-b5a9ad834dc8$tag$, $tag$2026010200037$tag$, $tag$Kedma Nobre (5581988380663)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Não consegui","time":"02/01/2026 13:59:34"},{"role":"client","text":"🌟 Boa tarde Kedma Nobre! Que alegria ter você aqui com a gente! 🙌","time":"02/01/2026 13:59:34"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"02/01/2026 13:59:38"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"02/01/2026 13:59:42"},{"role":"client","text":"Será que ainda consigo com esse valor?","time":"02/01/2026 13:59:43"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"02/01/2026 13:59:49"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"02/01/2026 14:00:03"},{"role":"client","text":"Olá! Kedma Nobre!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"02/01/2026 14:00:04"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"02/01/2026 14:00:08"},{"role":"client","text":"Falar com um atendente","time":"02/01/2026 14:00:22"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"02/01/2026 14:00:23"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"02/01/2026 14:04:31"},{"role":"client","text":"Oi Karina","time":"02/01/2026 14:04:50"},{"role":"client","text":"Eu fiz todos os passos da matrícula e não finalizei 😞","time":"02/01/2026 14:05:06"},{"role":"client","text":"Será que consigo fazer com o preço da black?","time":"02/01/2026 14:05:18"},{"role":"agent","text":"*Karina Pimentel:* Pelo valor da Black infelizmente não!","time":"02/01/2026 14:14:35","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"😔","time":"02/01/2026 14:14:55"},{"role":"client","text":"Quanto está a mensalidade da pós em educação clássica ?","time":"02/01/2026 14:15:34"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar ok!","time":"02/01/2026 14:15:56","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Karina Pimentel:* *Pós-graduação em Educação Cristã Clássica*.\n\n*NOTA MÁXIMA NO MEC*\nPós-graduação com a maior avaliação junto ao MEC, conceito 05 estrelas.\n\n*DURAÇÃO*\nO curso tem duração de 16 meses.\n\n*CARGA HORÁRIA*\nNossa carga horária é de 400h.\n\n*DISCIPLINAS*\nContamos com um total de 10 disciplinas.\n\n*AULAS*\nO curso é totalmente on-line e você pode assistir às aulas em qualquer dia e horário, pois ficarão gravadas dentro da plataforma.\n\n*AVALIAÇÕES*\nAs avaliações serão realizadas através de questões abertas, fechadas, fóruns e elaboração de textos. Todas as atividades serão realizadas dentro da plataforma educacional, assim, não é necessário ter um Polo da Faculdade em sua cidade.\n\n*NÃO É NECESSÁRIO TCC*\nDe acordo com a nova deliberação do MEC, a Resolução CNE/CES nº 1/2018, não há mais a obrigação de entrega de um TCC.","time":"02/01/2026 14:16:10","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* O valor de investimento na Pós-graduação em Educação Cristã Clássica está em 16 mensalidades de *R$ 479,16*. \n\nNão temos taxa de matrícula. Ao pagar a primeira mensalidade hoje, as próximas serão devidas a partir do início das aulas, previsto para Abril de 2026!","time":"02/01/2026 14:16:20","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:* Estamos com uma oferta especial essa semana, 20% de desconto nas mensalidades! 🤩\nMensalidades ficarão no valor de R$ 383,33.\nVamos garantir a sua vaga? 😊","time":"02/01/2026 14:16:30","feedback":"💡 Condução: Boa pergunta de engajamento para manter a conversa ativa."},{"role":"client","text":"Ta bom, obrigada","time":"02/01/2026 14:16:47"},{"role":"agent","text":"*Karina Pimentel:* Consigo 50% de desconto","time":"02/01/2026 14:16:59","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"50% fica mais viável pra min","time":"02/01/2026 14:17:51"},{"role":"client","text":"Com 50% fica viável, pra mim","time":"02/01/2026 14:18:19"},{"role":"agent","text":"*Karina Pimentel:* Ficará mensais de R$ 239,58","time":"02/01/2026 14:19:36","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"client","text":"Fica viável pra mim","time":"02/01/2026 14:20:00"},{"role":"client","text":"Como faço a matrícula?","time":"02/01/2026 15:19:30"},{"role":"agent","text":"*Karina Pimentel:* Vou lhe enviar o link ok!","time":"02/01/2026 15:29:33","feedback":"🎯 Direcionamento: Excelente tentativa de conduzir o cliente ao fechamento."},{"role":"agent","text":"*Karina Pimentel:* \n 🎁 Cupom de Desconto ECC: *BOLSA50*\n\n📌 Realize sua matrícula no link: bit.ly/InscricaoPosECC2024\n\n✅ Assim que você preencher os seus dados, o sistema disponibilizará o seu contrato para aceitação e o pagamento da primeira parcela, que pode ser feito por cartão ou boleto.","time":"02/01/2026 15:30:18","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Karina Pimentel:*  Espero ter atendido sua demanda. Caso tenha alguma outra dúvida ou solicitação, não hesite em entrar em contato novamente. Deus te abençoe. 😊","time":"02/01/2026 17:53:33","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nKedma Nobre, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"02/01/2026 17:53:34"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"02/01/2026 17:53:35"},{"role":"client","text":"Kedma Nobre, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"02/01/2026 18:08:35"}]$tag$, $tag$2026-01-02 13:59:34+00$tag$, FALSE, TRUE, 9, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 6, 9, 10, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.messag