INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$64387c09-6619-4b82-bd64-45bafaa190f0$tag$, $tag$2026010500019$tag$, $tag$Renelita Moesia 🥰 (5583994081300)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Oi, vim pelo Instagram e quero mais informações","time":"05/01/2026 09:03:59"},{"role":"client","text":"Bom dia","time":"05/01/2026 09:04:01"},{"role":"client","text":"🌟 Bom dia Renelita Moesia 🥰! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 09:04:00"},{"role":"client","text":"🌟 Bom dia Renelita Moesia 🥰! Que alegria ter você aqui com a gente! 🙌","time":"05/01/2026 09:04:02"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"05/01/2026 09:04:05"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"05/01/2026 09:04:09"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"05/01/2026 09:04:13"},{"role":"client","text":"Sou acadêmica em direito do 7 período","time":"05/01/2026 09:04:13"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"05/01/2026 09:04:13"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"05/01/2026 09:04:18"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"05/01/2026 09:04:24"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"05/01/2026 09:04:25"},{"role":"client","text":"Vou precisar transferir para JP","time":"05/01/2026 09:04:33"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.","time":"05/01/2026 09:04:34"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"05/01/2026 09:04:34"},{"role":"client","text":"Sim, concordo","time":"05/01/2026 09:04:53"},{"role":"client","text":"✅ Obrigado, Renelita Moesia 🥰! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"05/01/2026 09:04:54"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 09:04:57"},{"role":"client","text":"Sou graduada já em enfermagem","time":"05/01/2026 09:05:01"},{"role":"client","text":"Ops, não consegui entender sua mensagem. 😕 \n\nPor favor, selecione  *a opção desejada*  no menu anterior.\n","time":"05/01/2026 09:05:02"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"05/01/2026 09:05:02"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"05/01/2026 09:05:14"},{"role":"client","text":"Olá! Renelita Moesia 🥰!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"05/01/2026 09:05:16"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"05/01/2026 09:05:20"},{"role":"client","text":"Falar com um atendente","time":"05/01/2026 09:05:31"},{"role":"client","text":"Certo! 🙌\n\nEstamos localizando um atendente para falar com você.\n\nEnquanto isso, me diz rapidinho:\n💬 Sobre qual assunto você precisa de ajuda?\n","time":"05/01/2026 09:05:32"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"05/01/2026 09:05:32"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Thayanne Sales","time":"05/01/2026 09:30:33"},{"role":"agent","text":"*Thayanne Sales:* No que posso lhe ajudar?","time":"05/01/2026 09:30:37","feedback":"⚠️ Pergunta Genérica: Evite perguntas que podem ser respondidas com \"não\". Tente: \"Qual sua maior motivação para estudar hoje?\""},{"role":"client","text":"Quero transferir meu curso de Cajazeiras para JP","time":"05/01/2026 09:39:18"},{"role":"client","text":"Sou graduada já em enfermagem","time":"05/01/2026 09:39:24"},{"role":"client","text":"E estava no 7 período de direito","time":"05/01/2026 09:39:33"},{"role":"client","text":"Queria saber o que preciso solicitar na faculdade de Cajazeiras para na da e para de vcs","time":"05/01/2026 09:40:02"},{"role":"client","text":"E se tenho um desconto por ser graduada já como tenho na de Cajazeiras","time":"05/01/2026 09:40:22"},{"role":"client","text":"Não sei se vcs ofertam esse desconto para graduada","time":"05/01/2026 09:40:35"},{"role":"client","text":"Gostaria dessas informações","time":"05/01/2026 09:40:45"},{"role":"agent","text":"*Thayanne Sales:* *Bacharelado em Direito*\n\n*GRADUAÇÃO COM COSMOVISÃO CRISTÃ*\nValorização do Direito clássico, sem viés ideológico, o Direito tratado numa cosmovisão cristã.\n\n*NOTA MÁXIMA NO MEC*\nGraduação com a maior avaliação junto ao MEC, conceito 05 estrelas ( *bit.ly/3LlEgJS* ) com duração de 5 anos. \n\n*PRÁTICA JURÍDICA*\nÚnico curso no Brasil com vivência de prática jurídica do primeiro ao décimo período.\n\n*NÚCLEO*\nPrimeiro e único núcleo de prática jurídica em Lei Geral de Proteção de Dados (LGPD).\n\n*VOCAÇÃO*\nEspecialização durante a graduação com disciplinas optativas nas áreas: \n\na) Serviço Público; \nb) Advocacia Empreendedora; \nc) Academia\n\n*BIBLIOTECA DIGITAL*\nRevista dos Tribunais online e a Biblioteca Digital Proview da Revista dos Tribunais. Kindles com assinatura Unlimited.\n\n*AULAS PRESENCIAIS*\nDe segunda à sexta, das 19h às 22h - goo.gl/maps/tb5occMvgJGHsjwz9.","time":"05/01/2026 10:40:01","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* Segue a matriz curricular do curso de Direito *bit.ly/3SpepqX*","time":"05/01/2026 10:40:06","feedback":"✨ Atendimento Humanizado: Linguagem clara. Continue estimulando o desejo do cliente."},{"role":"agent","text":"*Thayanne Sales:* A mensalidade da Graduação em Direito está R$ 1.407,95. \n\n🤩 Estamos com uma condição excepcional, desconto de 60% na pontualidade durante toda graduação que ficará o valor de R$ 563,18.\n\nNão há taxa de matrícula, sendo a primeira mensalidade paga no ato da inscrição, e as demais mensalidades pagas até o dia 10 de cada mês.\n\n🌟 Valor promocional: (Semestralidade R$ 3.379,08).\n⚠️ Valor mensal está sujeito a mudança de acordo a data de matrícula:\n\n Matrículas realizadas até em JANEIRO: 6 mensalidades de R$ 563,18 = R$ 3.379,08\n Matrículas realizadas até em FEVEREIRO: 5 mensalidades de R$ 675,81 = R$ 3.379,08\nMatrículas realizadas até MARÇO: 04 mensalidades R$ 844,77 = R$ 3.3.79,08\n\nInício das aulas em Fevereiro de 2026 📚📖💻","time":"05/01/2026 10:40:12","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:* ✅ PROCEDIMENTO DE MATRÍCULA:\n\nRealize a matrícula de acordo com a sua forma de ingresso, basta acessar o link correspondente abaixo:\n\n1 - Aproveitamento do ENEM:\nbit.ly/FICV-Enem\n\n2 - Vestibular Agendado:\nbit.ly/FICV-Vestibular\n\n3 - Seleção de Graduados:\nbit.ly/FICV-Graduados\n\n📝 Após preencher seus dados, o sistema disponibilizará o pagamento da primeira parcela e o contrato para aceite. Não há cobrança de matrícula.😊","time":"05/01/2026 10:40:19","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"agent","text":"*Thayanne Sales:*   📌 Para realizar o aproveitamento de disciplinas você enviará o Requerimento de Aproveitamento de Estudos preenchido ( *https://bit.ly/Aproveitamento-FICV* ), junto com o histórico e o ementário das disciplinas desejadas para o e-mail:\n\nfaculdade@cidadeviva.org\n\nCom o assunto: Aproveitamento de disciplinas.","time":"05/01/2026 10:40:35","feedback":"🚩 Script Engessado: Você enviou um bloco grande de informações sem antes entender a dúvida real do cliente. Isso quebra o rapport."},{"role":"client","text":"Atendimento Finalizado!\n\nRenelita Moesia 🥰, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"06/01/2026 08:19:20"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"06/01/2026 08:19:21"},{"role":"client","text":"Renelita Moesia 🥰, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"06/01/2026 08:34:21"}]$tag$, $tag$2026-01-05 09:03:59+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 6, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclusion = EXCLUDED.overall_conclusion, improvements = EXCLUDED.improvements;
