INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$4eca4f65-9c90-445f-a908-35cd4a73b901$tag$, $tag$2026010300026$tag$, $tag$Edriane N Lira (5583986774527)$tag$, NULL, $tag$Karina Pimentel$tag$, $tag$[{"role":"client","text":"Oi, já preenchi meus dados na página Teologia Novo Testamento e quero mais informações.","time":"03/01/2026 15:59:43"},{"role":"client","text":"🌟 Boa tarde Edriane N Lira! Que alegria ter você aqui com a gente! 🙌","time":"03/01/2026 15:59:44"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"03/01/2026 15:59:48"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"03/01/2026 15:59:51"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"03/01/2026 15:59:55"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"03/01/2026 16:00:01"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"03/01/2026 16:00:07"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"03/01/2026 16:00:07"},{"role":"client","text":"Sim, concordo","time":"03/01/2026 16:01:20"},{"role":"client","text":"✅ Obrigado, Edriane N Lira! Agora que você concordou com os termos da LGPD, podemos continuar seu atendimento. ","time":"03/01/2026 16:01:21"},{"role":"client","text":"Agora, selecione no menu abaixo com qual área da Cidade Viva você deseja falar.","time":"03/01/2026 16:01:24"},{"role":"client","text":"Faculdade \n Faculdade Internacional Cidade Viva","time":"03/01/2026 16:01:41"},{"role":"client","text":"Olá! Edriane N Lira!👋\n É um prazer te receber aqui, na Faculdade Internacional Cidade Viva. 😊","time":"03/01/2026 16:01:42"},{"role":"client","text":"Escolha uma opção abaixo para continuarmos:","time":"03/01/2026 16:01:46"},{"role":"client","text":"Saber sobre os cursos","time":"03/01/2026 16:02:01"},{"role":"client","text":"Perfeito! Qual modalidade de curso você tem interesse?","time":"03/01/2026 16:02:06"},{"role":"client","text":"Pós-Graduação","time":"03/01/2026 16:02:17"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"03/01/2026 16:02:21"},{"role":"client","text":"Psicoteologia","time":"03/01/2026 16:02:58"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"03/01/2026 16:02:59"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"03/01/2026 16:03:03"},{"role":"client","text":"Arquivo de imagem | (https://igrejabatista.widechat.com.br/config/storage/view/69596818175753f28c05de7d)","time":"03/01/2026 16:03:52"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"03/01/2026 16:03:52"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"03/01/2026 16:03:56"},{"role":"client","text":"Vocês colocaram a opção psicoteologia","time":"03/01/2026 16:04:22"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"03/01/2026 16:04:22"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"03/01/2026 16:04:26"},{"role":"client","text":"História do Cristianismo","time":"03/01/2026 16:06:01"},{"role":"client","text":"Desculpe, não entendi a opção desejada.\nPor favor, selecione no menu abaixo a opção que mais adequa a sua necessidade.","time":"03/01/2026 16:06:02"},{"role":"client","text":"Esses são os cursos de *Pós-Graduação* que temos disponíveis no momento:","time":"03/01/2026 16:06:06"},{"role":"client","text":"Novo Testamento","time":"03/01/2026 16:06:10"},{"role":"client","text":"Estude profundamente o contexto, a teologia e a mensagem do Novo Testamento.\n\n 🔠 Com Grego Bíblico, exegese e interpretação textual\n 📚 Ideal para pastores, líderes e estudiosos da Bíblia\n 📅 Comece sua formação teológica ainda este ano\n","time":"03/01/2026 16:06:11"},{"role":"client","text":"Quer receber mais detalhes ou falar com um consultor?","time":"03/01/2026 16:06:15"},{"role":"client","text":"Quero saber mais \n Quero saber mais detalhes.","time":"03/01/2026 16:06:56"},{"role":"client","text":"Certo, em alguns instantes um dos nossos Consultores falará contigo.\nFique à vontade para interagir ou fazer alguma pergunta, OK?","time":"03/01/2026 16:06:57"},{"role":"client","text":"Aguarde só um momento!\n\nNeste instante, todos os nossos consultores estão prestando atendimento, o que pode gerar uma pequena espera.\n\nEstamos dedicando total atenção aos clientes que estão à sua frente. Assim que o próximo atendente estiver livre, ele irá assumir o seu chamado imediatamente.\n\nPedimos a sua compreensão e agradecemos por aguardar!","time":"03/01/2026 16:06:58"},{"role":"client","text":"Seja bem-vindo à Cidade Viva. Sou Karina Pimentel","time":"05/01/2026 09:31:38"},{"role":"agent","text":"*Karina Pimentel:* Olá Bom dia me chamo Karina Pimentel da Cidade Viva! \n","time":"05/01/2026 11:54:21","feedback":"🚩 Fechamento Ausente: O contato está terminando. Sempre faça um convite para o próximo passo."},{"role":"client","text":"Atendimento Finalizado!\n\nEdriane N Lira, esperamos que sua solicitação tenha sido totalmente resolvida.\n\nO seu feedback é muito importante para nós, então agradecemos se puder avaliar nosso atendimento em uma pesquisa futura.\n\nA FICV agradece o seu contato. Estamos sempre à disposição!","time":"05/01/2026 13:44:19"},{"role":"client","text":"Sua opinião é muito importante para nós.\nPor gentileza, avalie o atendimento realizado, considerando 1 como muito insatisfeito e 5 como muito satisfeito.","time":"05/01/2026 13:44:21"},{"role":"client","text":"Edriane N Lira, Obrigado pelo seu interesse na Cidade Viva.\n\nCaso deseje outra informação, não hesite em entrar em contato com a gente!\n  \nAté mais!","time":"05/01/2026 13:59:23"}]$tag$, $tag$2026-01-03 15:59:43+00$tag$, FALSE, FALSE, 8.2, $tag$2026-03-01 16:46:57.607947+00$tag$, 10, 10, 10, 2, 9, 1, $tag$65b591e2-df83-4fd5-9de1-52b0445d3ed1$tag$, $tag$approved$tag$, TRUE, NULL, '[]'::jsonb) ON CONFLICT (id) DO UPDATE SET protocol = EXCLUDED.protocol, contact = EXCLUDED.contact, agent_id = EXCLUDED.agent_id, agent_name = EXCLUDED.agent_name, message_content = EXCLUDED.message_content, timestamp = EXCLUDED.timestamp, has_empathy = EXCLUDED.has_empathy, closing_attempt = EXCLUDED.closing_attempt, final_score = EXCLUDED.final_score, created_at = EXCLUDED.created_at, empathy_score = EXCLUDED.empathy_score, clarity_score = EXCLUDED.clarity_score, depth_score = EXCLUDED.depth_score, commercial_score = EXCLUDED.commercial_score, agility_score = EXCLUDED.agility_score, message_count = EXCLUDED.message_count, upload_id = EXCLUDED.upload_id, status = EXCLUDED.status, is_commercial = EXCLUDED.is_commercial, overall_conclus