INSERT INTO public.messages_logs (id, protocol, contact, agent_id, agent_name, message_content, timestamp, has_empathy, closing_attempt, final_score, created_at, empathy_score, clarity_score, depth_score, commercial_score, agility_score, message_count, upload_id, status, is_commercial, overall_conclusion, improvements) VALUES ($tag$98acf222-6f4e-4e0d-8260-88d4b5d45e32$tag$, $tag$2026010400021$tag$, $tag$Joao Marcos (5588981029431)$tag$, NULL, $tag$Thayanne Sales$tag$, $tag$[{"role":"client","text":"Boa noite","time":"04/01/2026 21:28:59"},{"role":"client","text":"🌟 Boa noite Joao Marcos! Que alegria ter você aqui com a gente! 🙌","time":"04/01/2026 21:28:59"},{"role":"client","text":"Seja bem-vindo ao atendimento digital da Cidade Viva","time":"04/01/2026 21:29:03"},{"role":"client","text":"Você poderá tirar dúvidas sobre Igreja, Faculdade, Fundação, Livraria e nosso Sistema de Ensino.\n","time":"04/01/2026 21:29:07"},{"role":"client","text":"🔐 *Em conformidade com a Lei Geral de Proteção de Dados (LGPD), seus dados serão utilizados exclusivamente para fins de atendimento, tratados com segurança e nunca compartilhados com terceiros sem sua autorização.*","time":"04/01/2026 21:29:11"},{"role":"client","text":"Antes de seguirmos, pedimos apenas um minuto para conferir nossos Termos de Uso e Política de Privacidade. Neles, você encontra todos os detalhes sobre como tratamos seus dados em conformidade com a LGPD, seja para assuntos da Igreja, Escola, Fundação ou outras áreas da organização.","time":"04/01/2026 21:29:17"},{"role":"client","text":"Acesse o documento completo aqui: https://drive.google.com/file/d/1k1z1zHcYSVRfRcy8ZH_jridrI2xRP-en/view?usp=sharing \n\n✅ Ao continuar neste atendimento, você declara estar ciente e de acordo com estes termos.","time":"04/01/2026 21:29:22"},{"role":"client","text":"Você concorda com o uso dos seus dados conforme informado acima?","time":"04/01/2026 21:29:23"},{"role":"client","text":"Sim, concordo","time":"04/01/2026 21:31:35"},